#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        long long sum = 0, prod = 1;
        for(int i=0;i<N;i++){
            long long x; scanf("%lld", &x);
            sum += x;
            prod *= x;
        }
        printf("%lld %lld\n", sum, prod);
    }
    return 0;
}

